using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
    int components;

public:
    UnionFind(int size) : components(size) {
        parent.resize(size);
        rank.resize(size, 0);
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool unite(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) {
            return false;
        }
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
        components--;
        return true;
    }

    int getComponents() const {
        return components;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long left = 0;
    long long right = 1e6;
    long long answer = right;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind uf(n);
        for (const auto& edge : edges) {
            if (edge[2] <= mid) {
                uf.unite(edge[0], edge[1]);
            }
        }
        if (uf.getComponents() <= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

